/// {@category Containers}
library;

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/constants.dart';
import 'package:baseball_detector_flutter/controllers/maintenance_controller.dart';
import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller.dart';
import 'package:baseball_detector_flutter/controllers/version_controller.dart';
import 'package:baseball_detector_flutter/gen/assets.gen.dart';
import 'package:baseball_detector_flutter/providers/auth_client_provider.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/views/hooks/use_auth_navigation.dart';
import 'package:baseball_detector_flutter/views/hooks/use_effect_once.dart';
import 'package:baseball_detector_flutter/views/routers/app_router.dart';
import 'package:baseball_detector_flutter/views/themes/color_manager.dart';
import 'package:baseball_detector_flutter/views/themes/font_manager.dart';
import 'package:baseball_detector_flutter/views/themes/system_ui_overlay.dart';

class SplashPage extends HookConsumerWidget {
  const SplashPage({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final authNavigation = useAuthNavigation();
    useEffectOnce(() {
      SystemUiOverlayColorScheme.instance.lock(false);

      Future.delayed(const Duration(milliseconds: 2000), () async {
        // Navigate to force migration page
        if (Constants.isDeprecated) {
          if (!context.mounted) return;
          Navigator.of(context)
              .pushReplacementNamed(AppRouter.forceMigrationPage);
          return;
        }

        // if in maintenance, navigate to maintenance page asynchronously
        ref
            .refresh(maintenanceControllerProvider.notifier)
            .startObserving(false);
        ref.refresh(versionControllerProvider.notifier).startObserving(false);

        final authClient = ref.read(authClientProvider);
        final isLoggedIn = await authClient.isLoggedIn;

        // Already logged in
        if (isLoggedIn) {
          // Always refresh user's accessible contents for logged in users
          // Check if accessible contents were successfully loaded
          final hasAccessibleContents = await ref
              .read(userAccessibleContentsControllerProvider.notifier)
              .refresh();

          final page = hasAccessibleContents != null
              ? AppRouter.homePage
              : AppRouter.loginPage; // Fallback to login if refresh failed
          if (!context.mounted) return;
          Navigator.of(context).pushReplacementNamed(page);
          return;
        }

        final isOnboardingShown =
            ref.read(profileStorageProvider).getIsOnboardingPageShown();

        if (isOnboardingShown != true) {
          if (!context.mounted) return;
          Navigator.of(context).pushReplacementNamed(AppRouter.onboardingPage);
          return;
        }

        authNavigation();
      });

      return () {
        SystemUiOverlayColorScheme.instance.unlock();
      };
    });

    return Scaffold(
      backgroundColor: ColorManager.splashBackground,
      body: Center(
        child: SizedBox(
          width: 320,
          child: Column(
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              Center(child: Assets.images.imgAppLogoLight.svg(width: 320)),
              Align(
                  alignment: Alignment.topRight,
                  child: Text(
                    'by Knowhere',
                    style: TextStyleManager.headline6
                        .copyWith(height: 1, color: Colors.black),
                  )),

