part 'maintenance_controller.g.dart';

abstract class MaintenanceControllerHandlers {
  void onInMaintenance();

  void onMaintenanceEnded();
}

@Riverpod(keepAlive: true)
class MaintenanceController extends _$MaintenanceController {
  static const _interval = Duration(minutes: 5);
  static late MaintenanceControllerHandlers _handlers;
  static var _wasInMaintenanceLastTime = false;
  static Timer? _timer;

  bool _mounted = true;
  final _client = StaticFileClient();

  static void registerHandlers(MaintenanceControllerHandlers handlers) {
    _handlers = handlers;
  }

  @override
  AsyncValue<Result<Failure, MaintenanceInfo>> build() {
    _mounted = true;
    ref.onDispose(() => _mounted = false);

    if (_timer != null) {
      // reload and reset timer
      startObserving(true);
    } else {
      // reload
      _updateInfo();
    }
    return const AsyncValue.loading();
  }

  Future<void> _updateInfo() async {
    state = const AsyncValue.loading();
    final res = await _client.fetchMaintenanceInfo();
    if (_mounted) {
      state = AsyncValue.data(res);
    }
    if (res.hasRight) {
      if (res.right.isInMaintenance && !_wasInMaintenanceLastTime) {
        _handlers.onInMaintenance();
      } else if (!res.right.isInMaintenance && _wasInMaintenanceLastTime) {
        _handlers.onMaintenanceEnded();
      }
      _wasInMaintenanceLastTime = res.right.isInMaintenance;
    }
  }

  Future<void> startObserving([bool refreshImmediately = true]) async {
    stopObserving();
    _timer = Timer.periodic(_interval, (_) => _updateInfo());
    if (refreshImmediately) {
      await _updateInfo();
    }
  }

  void stopObserving() {
    _timer?.cancel();
    _timer = null;
  }

