    _mounted = true;
    ref.onDispose(() {
        _mounted = false;
        stopObserving();  // Dispose時にタイマーをクリーンアップ
    });

    // build()は初期化のみ、実際のチェックは外部から制御
    return const AsyncValue.loading();
}
```

**メリット**:
