### **ハイブリッドアプローチ（推奨）**

```dart
@Riverpod(keepAlive: true)
class VersionController extends _$VersionController {
    // ... 変数定義 ...

    static VersionControllerHandlers? _handlers;
    static final _initializationCompleter = Completer<void>();

    @override
    AsyncValue<Result<Failure, UpdateInfo>> build() {
        _mounted = true;
        ref.onDispose(() {
            _mounted = false;
            stopObserving();
        });

        return const AsyncValue.loading();
    }

    // 統合初期化メソッド（明示的に呼び出す）
    static Future<void> initializeApp({
        required VersionControllerHandlers handlers,
        required ProviderRef ref,
    }) async {
        // 既に初期化済みなら早期リターン
        if (_initializationCompleter.isCompleted) {
            _logger.w('VersionController already initialized');
            return;
        }

        try {
            _handlers = handlers;

            // Controllerインスタンスを取得して初期化
            final controller = ref.read(versionControllerProvider.notifier);
            await controller.startObserving(refreshImmediately: true);

            _initializationCompleter.complete();
            _logger.i('VersionController initialized successfully');
        } catch (e, stack) {
            _logger.e('Failed to initialize VersionController', ex: e, stacktrace: stack);
            // エラーでもCompleterは完了させる（再初期化を防ぐため）
            _initializationCompleter.completeError(e, stack);
            rethrow;
        }
    }

    // リセット用（テストなどで使用）
    @visibleForTesting
    static void reset() {
        _handlers = null;
        _initializationCompleter = Completer<void>();
        _isUpdateNotified = false;
        _isUpdateForced = false;
    }
}
```

### **main.dart での最終的な使用方法**

```dart
@override
void initState() {
    super.initState();
    WidgetsBinding.instance.addObserver(this);

    // 統合初期化メソッドを使用
    WidgetsBinding.instance.addPostFrameCallback((_) async {
        try {
            await Future.wait([
                MaintenanceController.initializeApp(
                    handlers: this,
                    ref: ref,
                ),
                VersionController.initializeApp(
                    handlers: this,
                    ref: ref,
                ),
            ]);
            _logger.i('All controllers initialized');
        } catch (e) {
            _logger.e('Controller initialization failed', ex: e);
            // エラーハンドリング
        }
    });
}

void _onResumed() {
    // 既に初期化されているので、監視再開のみ
    ref.read(maintenanceControllerProvider.notifier).startObserving(true);
    ref.read(versionControllerProvider.notifier).startObserving(true);
}
```

