        VersionControllerHandlers handlers,  // ← 引数として受け取る
    ) {
        _mounted = true;
        _handlers = handlers;  // ハンドラーを保存

        ref.onDispose(() {
            _mounted = false;
            stopObserving();
        });

        // 初期化と監視開始を自動実行
        Future.microtask(() async {
            await startObserving(refreshImmediately: true);
        });

        return const AsyncValue.loading();
    }

    // ハンドラー呼び出しを静的からインスタンスメソッドに変更
    void _notifyNewVersionRequired() {
        _handlers.onNewVersionRequired();
    }

    void _notifyNewVersionAvailable() {
        _handlers.onNewVersionAvailable();
    }

    // 他のメソッドは既存のまま...
}
```

### **2. 生成される Provider の使い方**

```dart
// 生成されるProviderは以下のような形になる
final versionControllerProvider = NotifierProvider.family<
    VersionController,
    AsyncValue<Result<Failure, UpdateInfo>>,
    VersionControllerHandlers
>.internal(
    VersionController.new,
    name: r'versionControllerProvider',
    // ...
);
```

### **3. main.dart での使用方法**

```dart
class _AppState extends ConsumerState<App>
    with WidgetsBindingObserver
    implements MaintenanceControllerHandlers, VersionControllerHandlers {

    // Provider参照を保持
    late final _versionControllerProvider = 
        versionControllerProvider(this);  // ← thisをハンドラーとして渡す

    @override
    void initState() {
        super.initState();
        WidgetsBinding.instance.addObserver(this);

        // Providerを読み込むだけで自動初期化される
        ref.read(_versionControllerProvider);
    }

    void _onResumed() {
        // 既存のインスタンスで監視再開
        ref.read(_versionControllerProvider.notifier).startObserving(true);
    }
}
```

## 代替案：Dependency Injection パターン

`★ Insight ─────────────────────────────────────`
- Provider Override を使った依存性注入
- よりテストしやすい設計
- Riverpod の標準パターンに沿った実装
`─────────────────────────────────────────────────`

### **Provider Override を使う方法**

```dart
// 1. ハンドラー用のProviderを定義
@Riverpod(keepAlive: true)
VersionControllerHandlers versionControllerHandlers(
    VersionControllerHandlersRef ref,
) {
    throw UnimplementedError('Must be overridden');
}

// 2. VersionControllerで使用
@Riverpod(keepAlive: true)
class VersionController extends _$VersionController {
    late final VersionControllerHandlers _handlers;

    @override
    AsyncValue<Result<Failure, UpdateInfo>> build() {
        _mounted = true;
        _handlers = ref.watch(versionControllerHandlersProvider);  // ← Providerから取得

        ref.onDispose(() {
            _mounted = false;
            stopObserving();
        });

        // 自動初期化
        Future.microtask(() async {
            await startObserving(refreshImmediately: true);
        });

        return const AsyncValue.loading();
    }
}

// 3. main.dartでOverride
Future<ProviderContainer> _createProviderContainer() async {
    final container = ProviderContainer(
        overrides: [
            sharedPreferencesProvider.overrideWithValue(
                await SharedPreferences.getInstance(),
            ),
            // ハンドラーをここでOverride
            versionControllerHandlersProvider.overrideWithValue(
                _AppState(),  // または専用のハンドラークラス
            ),
        ],
        // ...
    );
    return container;
}
```

## 比較と推奨

### **Family Provider アプローチ**
**メリット**:
- ✅ 直感的な引数渡し
- ✅ build メソッドで完結
- ✅ ハンドラーごとに別インスタンス

**デメリット**:
- ❌ Provider参照が複雑（引数付き）
- ❌ 他の場所から参照しづらい

### **Provider Override アプローチ**
**メリット**:
- ✅ Riverpod の標準パターン
- ✅ テストしやすい
- ✅ 依存関係が明確

**デメリット**:
- ❌ 初期設定がやや複雑
- ❌ Override忘れのリスク

### **現実的な実装案（シンプル版）**

```dart
@Riverpod(keepAlive: true)
class VersionController extends _$VersionController {
    // シンプルに静的変数で管理（現在の方式を改良）
    static VersionControllerHandlers? _handlers;
    static bool _isAutoInitialized = false;

    @override
    AsyncValue<Result<Failure, UpdateInfo>> build() {
        _mounted = true;
        ref.onDispose(() {
            _mounted = false;
            stopObserving();
        });

        // ハンドラーが登録済みで、まだ自動初期化していない場合
        if (_handlers != null && !_isAutoInitialized) {
            _isAutoInitialized = true;
            Future.microtask(() async {
                await startObserving(refreshImmediately: true);
            });
        }

        return const AsyncValue.loading();
    }

    // 使用側は従来通り
    static void registerHandlers(VersionControllerHandlers handlers) {
        _handlers = handlers;
        _isAutoInitialized = false;  // 次回build時に自動初期化
    }
}
```

**推奨**: シンプル版が最も実装しやすく、既存コードへの影響も最小限です。Family Provider は複雑になりがちなので、特別な理由がない限り避けるのが良いでしょう。

素晴らしい根本的な質問です！ハンドラーパターンの必要性を検証します。

`★ Insight ─────────────────────────────────────`
- ハンドラーパターンは Navigation を Controller から分離するため
- Riverpod + Navigator の組み合わせには代替手段がある
- 現代的な Flutter では不要な複雑さかもしれない
`─────────────────────────────────────────────────`

## 現在のハンドラーパターンの問題点

### 1. **複雑な初期化フロー**
```dart
// 現在の複雑なフロー
1. _AppState が VersionControllerHandlers を実装
2. initState() で registerHandlers() 呼び出し
3. VersionController が静的変数で保持
4. バージョンチェック時に _handlers.onNewVersionRequired() 呼び出し
5. _AppState.onNewVersionRequired() で Navigation
```

### 2. **静的変数による結合**
- Controller と View が静的変数で強く結合
- テストが困難
- 複数インスタンスを持てない

## 代替案の検討

### **案1: Provider で状態を監視（推奨）** ✨

```dart
// VersionController - シンプルに状態を管理
@Riverpod(keepAlive: true)
class VersionController extends _$VersionController {
    @override
    AsyncValue<VersionState> build() {
        _startObserving();
        return const AsyncValue.loading();
    }

    Future<void> _updateInfo() async {
        final info = await _fetchVersionInfo();

        if (info.requiresUpdate) {
            state = AsyncValue.data(VersionState.updateRequired(info));
        } else if (info.hasNewVersion) {
            state = AsyncValue.data(VersionState.updateAvailable(info));
        } else {
            state = AsyncValue.data(VersionState.upToDate(info));
        }
    }
}

// _AppState - Provider を監視して Navigation
class _AppState extends ConsumerState<App> {
    @override
    Widget build(BuildContext context) {
        // バージョン状態を監視
        ref.listen(versionControllerProvider, (previous, next) {
            if (next.hasValue) {
                switch (next.value!) {
                    case VersionState.updateRequired:
                        Navigator.pushNamed(context, AppRouter.updateRequiredPage);
                    case VersionState.updateAvailable:
                        _showUpdateDialog();
                }
            }
        });

        return MaterialApp(...);
    }
}
```

**メリット**:
- ✅ シンプルで理解しやすい
- ✅ Riverpod の標準パターン
- ✅ テストしやすい
- ✅ 静的変数不要

### **案2: StreamController パターン**

```dart
@Riverpod(keepAlive: true)
class VersionController extends _$VersionController {
    final _navigationEvents = StreamController<NavigationEvent>.broadcast();
    Stream<NavigationEvent> get navigationEvents => _navigationEvents.stream;

    Future<void> _updateInfo() async {
        final info = await _fetchVersionInfo();

        if (info.requiresUpdate) {
            _navigationEvents.add(NavigationEvent.forceUpdate());
        }
    }
}

// main.dart
@override
void initState() {
    super.initState();

    ref.read(versionControllerProvider.notifier)
        .navigationEvents
        .listen((event) {
            // Navigation 処理
        });
}
```

### **案3: グローバル Navigation キーのみ使用**

```dart
class VersionController extends _$VersionController {
    Future<void> _updateInfo() async {
        final info = await _fetchVersionInfo();

        if (info.requiresUpdate) {
            // 直接 Navigation（シンプルだが責任が曖昧）
            appRouterKey.currentState?.pushNamed(AppRouter.updateRequiredPage);
        }
    }
}
```

## 比較分析

`★ Insight ─────────────────────────────────────`
- ref.listen パターンが最も Riverpod らしい
- ハンドラーパターンは過度な抽象化の可能性
- シンプルさとテスタビリティのバランスが重要
`─────────────────────────────────────────────────`

| アプローチ | 複雑さ | テスタビリティ | 保守性 | Riverpod親和性 |
|----------|-------|--------------|--------|---------------|
| 現在のハンドラー | 高 | 低 | 低 | 低 |
| ref.listen | **低** | **高** | **高** | **高** |
| Stream | 中 | 中 | 中 | 中 |
| 直接Navigation | 低 | 低 | 低 | 低 |

## 結論と推奨

**ハンドラーパターンは不要です。** `ref.listen` パターンへの移行を推奨します。

### 理由：
1. **Riverpod の標準的な使い方**に沿っている
2. **静的変数を排除**できる
3. **テストが簡単**（MockProvider で置き換え可能）
4. **責任が明確**（Controller は状態管理、View は Navigation）
5. **初期化が単純**（特別な登録処理不要）

### 実装例：

```dart
// 新しい VersionController（シンプル！）
@Riverpod(keepAlive: true)
class VersionController extends _$VersionController {
    Timer? _timer;
    bool _mounted = true;

    @override
    AsyncValue<VersionState> build() {
        ref.onDispose(() {
            _mounted = false;
            _timer?.cancel();
        });

        // 自動的に監視開始
        _startObserving();
        return const AsyncValue.loading();
    }

    void _startObserving() {
        _updateInfo();  // 初回チェック
        _timer = Timer.periodic(_interval, (_) => _updateInfo());
    }

    Future<void> _updateInfo() async {
        final info = await _fetchVersionInfo();
        if (!_mounted) return;

        state = AsyncValue.data(
            VersionState.fromInfo(info)
        );
    }
}

// main.dart（ハンドラー不要！）
class _AppState extends ConsumerState<App> with WidgetsBindingObserver {
    @override
    void initState() {
        super.initState();
        WidgetsBinding.instance.addObserver(this);
        // ハンドラー登録不要！
    }

    @override
    Widget build(BuildContext context) {
        // バージョン状態の監視
        ref.listen(versionControllerProvider, (_, next) {
            _handleVersionState(next);
        });

        return MaterialApp(...);
    }
}
```

これにより、コードが **50% 以上削減** され、理解しやすくなります。

