library;

// Dart imports:
import 'dart:async';

// Package imports:
import 'package:fimber/fimber.dart';
import 'package:package_info_plus/package_info_plus.dart';
import 'package:pub_semver/pub_semver.dart';
import 'package:riverpod_annotation/riverpod_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/clients/static_file_client.dart';
import 'package:baseball_detector_flutter/data/models/version_state.dart';
import 'package:baseball_detector_flutter/utils/platform.dart';

part 'version_controller.g.dart';

@Riverpod(keepAlive: true)
class VersionController extends _$VersionController {
  static final _logger = FimberLog('VersionController');
  static const _interval = Duration(minutes: 5);

  Timer? _timer;
  bool _mounted = true;
  final _client = StaticFileClient();

  // フラグ管理（アプリ全体で共有する必要があるため静的）
  static bool _isUpdateNotified = false;
  static bool _isUpdateForced = false;

  @override
  VersionState build() {
    _mounted = true;
    ref.onDispose(() {
      _mounted = false;
      stopObserving();
    });

    // 初回チェックを開始
    Future.microtask(() => startObserving(refreshImmediately: true));

    return const VersionState.checking();
  }

  Future<void> _updateInfo() async {
    if (!_mounted) return;

    state = const VersionState.checking();

    try {
      final res = await _client.fetchVersionInfo();

      if (!res.hasRight) {
        if (_mounted) {
          state = VersionState.error(
            message: res.left.message,
          );
        }
        return;
      }

      final platform = isAndroid
          ? res.right.android
          : isIos
              ? res.right.ios
              : throw Exception('unsupported platform');

      final packageInfo = await PackageInfo.fromPlatform();
      final currentVersion = _parseVersion(
        'current',
        '${packageInfo.version}+${packageInfo.buildNumber}'
      );

      if (currentVersion == null) {
        if (_mounted) {
          state = VersionState.error(
            message: 'Failed to parse current version',
            currentVersion: '${packageInfo.version}+${packageInfo.buildNumber}',
          );
        }
        return;
      }

      final requiredVersion = _parseVersion('required', platform.required);
      final latestVersion = _parseVersion('latest', platform.latest);

      // 状態を判定して更新
      if (requiredVersion != null && requiredVersion > currentVersion) {
        if (!_isUpdateForced) {
          _isUpdateForced = true;
          stopObserving(); // 強制アップデート時は監視を停止
        }

        if (_mounted) {
          state = VersionState.updateRequired(
            currentVersion: currentVersion.toString(),
            requiredVersion: requiredVersion.toString(),
            latestVersion: (latestVersion ?? currentVersion).toString(),
          );
        }
      } else if (latestVersion != null && latestVersion > currentVersion) {
        if (!_isUpdateNotified) {
          _isUpdateNotified = true;
        }

        if (_mounted) {
          state = VersionState.updateAvailable(
            currentVersion: currentVersion.toString(),
            latestVersion: latestVersion.toString(),
          );
        }
      } else {
        // 最新バージョンを使用中
        if (_mounted) {
          state = VersionState.upToDate(
            currentVersion: currentVersion.toString(),
            latestVersion: (latestVersion ?? currentVersion).toString(),
          );
        }

        // 強制アップデートが解除された場合
        if (_isUpdateForced && requiredVersion != null && requiredVersion <= currentVersion) {
          reset();
        }
      }
    } catch (e, stackTrace) {
      _logger.e('Failed to update version info', ex: e, stacktrace: stackTrace);
      if (_mounted) {
        state = VersionState.error(
          message: e.toString(),
        );
      }
    }
  }

  Version? _parseVersion(String type, String? source) {
    try {
      return source != null ? Version.parse(source) : null;
    } catch (e, stackTrace) {
      _logger.e('failed to parse $type version', ex: e, stacktrace: stackTrace);
      return null;
    }
  }

  Future<void> startObserving([bool refreshImmediately = true]) async {
    stopObserving();

    if (!_isUpdateForced) {
      _timer = Timer.periodic(_interval, (_) => _updateInfo());
    }

    if (refreshImmediately) {
      await _updateInfo();
    }
  }

  void stopObserving() {
    _timer?.cancel();
    _timer = null;
  }

  static void reset() {
    _isUpdateNotified = false;
    _isUpdateForced = false;
  }
}

