@freezed
sealed class MaintenanceState with _$MaintenanceState {
  /// 通常運用中
  const factory MaintenanceState.operational() = Operational;

  /// メンテナンス中
  const factory MaintenanceState.inMaintenance({
    String? message,
    DateTime? estimatedEndTime,
  }) = InMaintenance;

  /// メンテナンス情報確認中
  const factory MaintenanceState.checking() = CheckingMaintenance;

  /// エラー発生
  const factory MaintenanceState.error({
    required String message,
  }) = MaintenanceError;
}

