// Project imports:
import 'package:baseball_detector_flutter/controllers/version_controller.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/views/components/custom_dialog.dart';
import 'package:baseball_detector_flutter/views/hooks/use_max_text_width.dart';
import 'package:baseball_detector_flutter/views/hooks/use_store_url.dart';
import 'package:baseball_detector_flutter/views/themes/font_manager.dart';
import 'package:flutter/material.dart';
// Package imports:
import 'package:hooks_riverpod/hooks_riverpod.dart';

class UpdateAvailableDialog extends HookConsumerWidget {
  const UpdateAvailableDialog({
    required this.updateInfo,
    super.key,
  });

  final UpdateInfo updateInfo;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final calculateMaxTextWidth = useMaxTextWidth();
    final openStoreUrl = useStoreUrl();
    return CustomDialog.normal(
      title: context.l10n.update_available_dialog__title,
      aboveButtonText: context.l10n.update_available_dialog__above_button_label,
      builder: (context, _) {
        final currentVersionText = TextSpan(
          text: context.l10n.update_available_dialog__current_version,
          style: TextStyleManager.subtitle2,
        );
        final latestVersionText = TextSpan(
          text: context.l10n.update_available_dialog__latest_version,
          style: TextStyleManager.subtitle2,
        );
        final nameWidth = calculateMaxTextWidth([
          currentVersionText,
          latestVersionText,
        ]);

        return Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
