            ...maintenanceState.when(
              checking: () => [const CustomLoadingIndicator()],
              operational: () => [
                Text(
                  context.l10n.maintenance_page__no_maintenance,
                  style: TextStyleManager.body1,
                ),
                const SizedBox(height: 16),
                _buildReloadButton(context),
              ],
              inMaintenance: (message, estimatedEndTime) => [
                ..._buildMaintenanceContent(context, message, estimatedEndTime),
                const SizedBox(height: 16),
                _buildReloadButton(context),
              ],
              error: (message) => [
                Text(
                  message,
                  style: TextStyleManager.body1,
                ),
                const SizedBox(height: 16),
                _buildReloadButton(context),
              ],
            ),
          ],
        ),
      ),
    );
  }

  Iterable<Widget> _buildMaintenanceContent(
    BuildContext context,
    String? message,
    DateTime? estimatedEndTime,
  ) {
    final items = <Widget>[];

    // メンテナンスメッセージ
    if (message != null && message.isNotEmpty) {
      items.add(
        Text(
          message,
          style: TextStyleManager.body1,
        ),
      );
      items.add(const SizedBox(height: 8));
    }

    // 終了予定時刻
    if (estimatedEndTime != null) {
      items.add(
        Text(
          context.l10n.maintenance_page__until +
              dateTimeToString(
                timestamp: estimatedEndTime,
                locale: Localizations.localeOf(context).languageCode,
                template: context.l10n.datetime_format,
              ),
          style: TextStyleManager.body1,
        ),
      );
    }

    return items;
  }

  Widget _buildReloadButton(BuildContext context) {
    return CustomButton(
      variant: CustomButtonVariant.primary,
      onPressed: () => _onRefresh(),
      text: context.l10n.maintenance_page__reload,
    );
  }

  void _onRefresh() {
    ref.invalidate(maintenanceControllerProvider);
  }
}

