@freezed
abstract class ScheduledMaintenance with _$ScheduledMaintenance {
  @JsonSerializable(fieldRename: FieldRename.none, explicitToJson: true)
  factory ScheduledMaintenance({
    DateTime? since,
    DateTime? until,
    Map<String, String>? description,
  }) = _ScheduledMaintenance;

  factory ScheduledMaintenance.fromJson(Map<String, dynamic> json) =>
      _$ScheduledMaintenanceFromJson(json);
}

