Future<void> _updateInfo() async {
  if (!_mounted) return;

  state = const MaintenanceState.checking();

  try {
    final res = await _client.fetchMaintenanceInfo();

    if (!res.hasRight) {
      if (_mounted) {
        state = MaintenanceState.error(
          message: res.left.message,
        );
      }
      return;
    }

    final maintenanceInfo = res.right;
    final newState = _convertToMaintenanceState(maintenanceInfo);

    if (_mounted) {
      state = newState;
    }

    // 状態変化の記録
    _wasInMaintenanceLastTime = maintenanceInfo.isInMaintenance;
  } catch (e, stackTrace) {
    _logger.e('Failed to update maintenance info', ex: e, stacktrace: stackTrace);
    if (_mounted) {
      state = MaintenanceState.error(
        message: e.toString(),
      );
    }
  }
}

/// MaintenanceInfo を MaintenanceState に変換
MaintenanceState _convertToMaintenanceState(MaintenanceInfo info) {
  if (!info.isInMaintenance) {
    return const MaintenanceState.operational();
  }

  // メンテナンス中の場合、最新のスケジュールから情報を取得
  final currentMaintenance = _getCurrentMaintenance(info.scheduledMaintenances);

  if (currentMaintenance != null) {
    return MaintenanceState.inMaintenance(
      message: _getMaintenanceMessage(currentMaintenance),
      estimatedEndTime: currentMaintenance.until,
    );
  }

  // スケジュール情報がない場合のフォールバック
  return const MaintenanceState.inMaintenance(
    message: 'System is currently under maintenance',
  );
}

/// 現在のメンテナンススケジュールを取得
ScheduledMaintenance? _getCurrentMaintenance(List<ScheduledMaintenance> schedules) {
  final now = DateTime.now();

  // 現在時刻が範囲内のメンテナンスを探す
  for (final schedule in schedules) {
    final since = schedule.since;
    final until = schedule.until;

    // since が null の場合は開始時刻制限なし
    final isAfterStart = since == null || now.isAfter(since);
    // until が null の場合は終了時刻制限なし
    final isBeforeEnd = until == null || now.isBefore(until);

    if (isAfterStart && isBeforeEnd) {
      return schedule;
    }
  }

  // 該当するスケジュールがない場合は最初のものを返す
  return schedules.isNotEmpty ? schedules.first : null;
}

/// メンテナンスメッセージを取得（多言語対応）
String? _getMaintenanceMessage(ScheduledMaintenance maintenance) {
  final descriptions = maintenance.description;
  if (descriptions == null || descriptions.isEmpty) {
    return null;
  }

  // TODO: 実際のロケール情報を取得する実装が必要
  // 現在は簡易的に日本語 → 英語 → 最初の値の順で取得
  return descriptions['ja'] ??
         descriptions['en'] ??
         descriptions.values.first;
}

