/// {@category Controllers}
library;

// Dart imports:
import 'dart:async';

// Package imports:
import 'package:fimber/fimber.dart';
import 'package:riverpod_annotation/riverpod_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/clients/static_file_client.dart';
import 'package:baseball_detector_flutter/data/models/maintenance_state.dart';

part 'maintenance_controller.g.dart';

@Riverpod(keepAlive: true)
class MaintenanceController extends _$MaintenanceController {
  static final _logger = FimberLog('MaintenanceController');
  static const _interval = Duration(minutes: 5);

  Timer? _timer;
  bool _mounted = true;
  final _client = StaticFileClient();

  // 前回の状態を記録（状態変化検出のため）
  static bool _wasInMaintenanceLastTime = false;

  @override
  MaintenanceState build() {
    _mounted = true;
    ref.onDispose(() {
      _mounted = false;
      stopObserving();
    });

    // 初回チェックを開始
    Future.microtask(() => startObserving(refreshImmediately: true));

    return const MaintenanceState.checking();
  }

  Future<void> _updateInfo() async {
    if (!_mounted) return;

    state = const MaintenanceState.checking();

    try {
      final res = await _client.fetchMaintenanceInfo();

      if (!res.hasRight) {
        if (_mounted) {
          state = MaintenanceState.error(
            message: res.left.message,
          );
        }
        return;
      }

      final maintenanceInfo = res.right;

      if (maintenanceInfo.isInMaintenance) {
        if (_mounted) {
          state = MaintenanceState.inMaintenance(
            message: maintenanceInfo.message,
            // estimatedEndTime は MaintenanceInfo に含まれていない場合は null
          );
        }
        _wasInMaintenanceLastTime = true;
      } else {
        if (_mounted) {
          state = const MaintenanceState.operational();
        }
        _wasInMaintenanceLastTime = false;
      }
    } catch (e, stackTrace) {
      _logger.e('Failed to update maintenance info', ex: e, stacktrace: stackTrace);
      if (_mounted) {
        state = MaintenanceState.error(
          message: e.toString(),
        );
      }
    }
  }

  Future<void> startObserving([bool refreshImmediately = true]) async {
    stopObserving();
    _timer = Timer.periodic(_interval, (_) => _updateInfo());

    if (refreshImmediately) {
      await _updateInfo();
    }
  }

  void stopObserving() {
    _timer?.cancel();
    _timer = null;
  }

  static void reset() {
    _wasInMaintenanceLastTime = false;
  }
}

