/// アプリのバージョン状態を表すsealed class
sealed class VersionState {}

/// 最新バージョンを使用中
class UpToDate extends VersionState {
  final String currentVersion;
  final String latestVersion;

  const UpToDate({
    required this.currentVersion,
    required this.latestVersion,
  });

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is UpToDate &&
          currentVersion == other.currentVersion &&
          latestVersion == other.latestVersion;

  @override
  int get hashCode => Object.hash(currentVersion, latestVersion);

  @override
  String toString() => 'UpToDate(currentVersion: $currentVersion, latestVersion: $latestVersion)';
}

/// 新しいバージョンが利用可能（任意アップデート）
class UpdateAvailable extends VersionState {
  final String currentVersion;
  final String latestVersion;

  const UpdateAvailable({
    required this.currentVersion,
    required this.latestVersion,
  });

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is UpdateAvailable &&
          currentVersion == other.currentVersion &&
          latestVersion == other.latestVersion;

  @override
  int get hashCode => Object.hash(currentVersion, latestVersion);

  @override
  String toString() => 'UpdateAvailable(currentVersion: $currentVersion, latestVersion: $latestVersion)';
}

/// アップデートが必須
class UpdateRequired extends VersionState {
  final String currentVersion;
  final String requiredVersion;
  final String latestVersion;

  const UpdateRequired({
    required this.currentVersion,
    required this.requiredVersion,
    required this.latestVersion,
  });

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is UpdateRequired &&
          currentVersion == other.currentVersion &&
          requiredVersion == other.requiredVersion &&
          latestVersion == other.latestVersion;

  @override
  int get hashCode => Object.hash(currentVersion, requiredVersion, latestVersion);

  @override
  String toString() => 'UpdateRequired(currentVersion: $currentVersion, requiredVersion: $requiredVersion, latestVersion: $latestVersion)';
}

/// バージョン情報取得中
class Checking extends VersionState {
  const Checking();

  @override
  bool operator ==(Object other) => identical(this, other) || other is Checking;

  @override
  int get hashCode => 0;

  @override
  String toString() => 'Checking()';
}

/// エラー発生
class VersionError extends VersionState {
  final String message;
  final String? currentVersion;

  const VersionError({
    required this.message,
    this.currentVersion,
  });

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is VersionError &&
          message == other.message &&
          currentVersion == other.currentVersion;

  @override
  int get hashCode => Object.hash(message, currentVersion);

  @override
  String toString() => 'VersionError(message: $message, currentVersion: $currentVersion)';
}

/// VersionState のパターンマッチング用拡張
extension VersionStateMatch on VersionState {
  T when<T>({
    required T Function(String currentVersion, String latestVersion) upToDate,
    required T Function(String currentVersion, String latestVersion) updateAvailable,
    required T Function(String currentVersion, String requiredVersion, String latestVersion) updateRequired,
    required T Function() checking,
    required T Function(String message, String? currentVersion) error,
  }) {
    return switch (this) {
      UpToDate(currentVersion: final current, latestVersion: final latest) =>
        upToDate(current, latest),
      UpdateAvailable(currentVersion: final current, latestVersion: final latest) =>
        updateAvailable(current, latest),
      UpdateRequired(currentVersion: final current, requiredVersion: final required, latestVersion: final latest) =>
        updateRequired(current, required, latest),
      Checking() =>
        checking(),
      VersionError(message: final message, currentVersion: final current) =>
        error(message, current),
    };
  }

  T maybeWhen<T>({
    T Function(String currentVersion, String latestVersion)? upToDate,
    T Function(String currentVersion, String latestVersion)? updateAvailable,
