        updateRequired?.call(current, required, latest) ?? orElse(),
      Checking() =>
        checking?.call() ?? orElse(),
      VersionError(message: final message, currentVersion: final current) =>
        error?.call(message, current) ?? orElse(),
    };
  }
}

