/// {@category Data}
library;

// Dart imports:
import 'dart:io';
import 'dart:math';

// Package imports:
import 'package:dio/dio.dart';
import 'package:fimber/fimber.dart';
import 'package:path/path.dart';
import 'package:path_provider/path_provider.dart';

// Project imports:
import 'package:baseball_detector_flutter/constants.dart';
import 'package:baseball_detector_flutter/data/clients/background_http_client.dart';
import 'package:baseball_detector_flutter/data/clients/http_client.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure_code.dart';
import 'package:baseball_detector_flutter/data/models/maintenance_info.dart';
import 'package:baseball_detector_flutter/data/models/version_info.dart';
import 'package:baseball_detector_flutter/data/query_runner.dart';
import 'package:baseball_detector_flutter/data/result.dart';

class StaticFileClient with BackgroundHttpClient, HttpClient {
  static final _logger = FimberLog('StaticFileClient');
  static final _fc =
      failureCodeBuilder.category('DSFC'); // Data-StaticFileClient

  final runner = QueryRunner();

  Future<Result<Failure, MaintenanceInfo>> fetchMaintenanceInfo() {
    return _fetchJson(
      url: Constants.maintenanceInfoURL,
      responseMapper: MaintenanceInfo.fromJson,
    );
  }

  Future<Result<Failure, VersionInfo>> fetchVersionInfo() {
    return _fetchJson(
      url: Constants.versionInfoURL,
      responseMapper: VersionInfo.fromJson,
    );
  }

  Future<Result<Failure, void>> saveAsFile({
    required String url,
    Map<String, dynamic>? queryParameters,
    required String savePath,
    CancelToken? cancelToken,
    void Function(double)? onProgress,
  }) async {
    final methodFc = _fc.category('SAF'); // SaveAsFile

    // NOTE: Download to a temporary file and move it once the download is complete
    // This is to prevent incomplete files from being recognized as cache even
    // when the app is abnormally terminated
    final tempFilename = '${Random.secure().nextInt(0xffffffff)}.tmp';
    final tempPath = join((await getTemporaryDirectory()).path, tempFilename);

    try {
      final result = await runner.runQuery(
        () => download(
          url: url,
          queryParameters: queryParameters,
          savePath: tempPath,
          cancelToken: cancelToken,
          onProgress: onProgress,
        ),
      );
      if (result.hasLeft) {
        return Left(result.left);
      }

      // Move the temporary file to intended download location
      final saveDir = dirname(savePath);
      await Directory(saveDir).create();
      await File(tempPath).rename(savePath);

      return const Right(null);
    } catch (e, stackTrace) {
      _logger.w('unexpected result', ex: e, stacktrace: stackTrace);
      return Left(Failure.undefined(
        code: methodFc.position('001'),
        underlyingException: e,
      ));
    } finally {
      // Delete the temporary file
      try {
        final tempFile = File(tempPath);
        if (await tempFile.exists()) {
          await File(tempPath).delete();
        }
      } catch (e, stackTrace) {
        _logger.w('failed to delete temporary file',
            ex: e, stacktrace: stackTrace);
      }
    }
  }

  Future<Result<Failure, T>> _fetchJson<T>({
    required String url,
    required T Function(Map<String, dynamic>) responseMapper,
  }) async {
    return runner.runQuery(
      () => fetch(
        url: url,
        responseMapper: responseMapper,
      ),
    );
  }
}

