// Package imports:
import 'package:flutter_test/flutter_test.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';
import 'package:package_info_plus/package_info_plus.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/version_controller.dart';
import 'package:baseball_detector_flutter/data/clients/static_file_client_fake.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/version_info.dart';
import 'package:baseball_detector_flutter/data/models/version_state.dart';
import 'package:baseball_detector_flutter/providers/static_file_client_provider.dart';

void main() {
  TestWidgetsFlutterBinding.ensureInitialized();

  late ProviderContainer container;
  late FakeStaticFileClient fakeStaticFileClient;

  setUp(() {
    fakeStaticFileClient = FakeStaticFileClient();

    // PackageInfo のモック設定
    PackageInfo.setMockInitialValues(
      appName: 'Baseball Detector',
      packageName: 'com.example.baseball_detector',
      version: '1.0.0',
      buildNumber: '10',
      buildSignature: '',
    );

    container = ProviderContainer(
      overrides: [
        staticFileClientProvider.overrideWithValue(fakeStaticFileClient),
      ],
    );
  });

  tearDown(() {
    container.dispose();
    fakeStaticFileClient.reset();
  });

  group('VersionController with FakeStaticFileClient', () {
    group('デフォルト動作', () {
      test('設定なしでデフォルト値を返す', () async {
        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(versionControllerProvider);
        expect(state, isA<UpToDate>());
        final upToDate = state as UpToDate;
        expect(upToDate.currentVersion, '1.0.0+10');
        expect(upToDate.latestVersion, '1.0.0+10');
      });
    });

    group('成功パターン', () {
      test('任意アップデート可能', () async {
        // Arrange
        fakeStaticFileClient.setVersionInfo(
          VersionInfo(
            android: VersionInfoPlatform(
              required: '1.0.0+10',
              latest: '1.1.0+15',
            ),
            ios: VersionInfoPlatform(
              required: '1.0.0+10',
              latest: '1.1.0+15',
            ),
          ),
        );

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(versionControllerProvider);
        expect(state, isA<UpdateAvailable>());
        final updateAvailable = state as UpdateAvailable;
        expect(updateAvailable.currentVersion, '1.0.0+10');
        expect(updateAvailable.latestVersion, '1.1.0+15');
      });

      test('強制アップデート必要', () async {
        // Arrange
        fakeStaticFileClient.setVersionInfo(
          VersionInfo(
            android: VersionInfoPlatform(
              required: '1.2.0+20',
              latest: '1.2.0+20',
            ),
            ios: VersionInfoPlatform(
              required: '1.2.0+20',
              latest: '1.2.0+20',
            ),
          ),
        );

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(versionControllerProvider);
        expect(state, isA<UpdateRequired>());
        final updateRequired = state as UpdateRequired;
        expect(updateRequired.currentVersion, '1.0.0+10');
        expect(updateRequired.requiredVersion, '1.2.0+20');
        expect(updateRequired.latestVersion, '1.2.0+20');
      });

      test('最新バージョン使用中', () async {
        // Arrange
        fakeStaticFileClient.setVersionInfo(
          VersionInfo(
            android: VersionInfoPlatform(
              required: '1.0.0+10',
              latest: '1.0.0+10',
            ),
            ios: VersionInfoPlatform(
              required: '1.0.0+10',
              latest: '1.0.0+10',
            ),
          ),
        );

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(versionControllerProvider);
        expect(state, isA<UpToDate>());
      });
    });

    group('エラーパターン', () {
      test('バージョン情報取得エラー', () async {
        // Arrange
        fakeStaticFileClient.setVersionFailure(
          Failure.undefined(
            code: 'NETWORK_ERROR',
            message: 'Network connection failed',
          ),
        );

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(versionControllerProvider);
        expect(state, isA<VersionError>());
        final versionError = state as VersionError;
        expect(versionError.message, 'Network connection failed');
      });

      test('現在のバージョンが無効な場合', () async {
        // Arrange
        PackageInfo.setMockInitialValues(
          appName: 'Baseball Detector',
          packageName: 'com.example.baseball_detector',
          version: 'invalid',
          buildNumber: 'invalid',
          buildSignature: '',
        );

        fakeStaticFileClient.setVersionInfo(
          VersionInfo(
            android: VersionInfoPlatform(
              required: '1.0.0+10',
              latest: '1.1.0+15',
            ),
            ios: VersionInfoPlatform(
              required: '1.0.0+10',
              latest: '1.1.0+15',
            ),
          ),
        );

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(versionControllerProvider);
        expect(state, isA<VersionError>());
        final versionError = state as VersionError;
        expect(versionError.message, 'Failed to parse current version');
        expect(versionError.currentVersion, 'invalid+invalid');
      });
    });

    group('エッジケース', () {
      test('required と latest が null の場合', () async {
        // Arrange
        fakeStaticFileClient.setVersionInfo(
          VersionInfo(
            android: VersionInfoPlatform(
              required: null,
              latest: null,
            ),
            ios: VersionInfoPlatform(
              required: null,
              latest: null,
            ),
          ),
        );

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(versionControllerProvider);
        expect(state, isA<UpToDate>());
        final upToDate = state as UpToDate;
        expect(upToDate.currentVersion, '1.0.0+10');
        expect(upToDate.latestVersion, '1.0.0+10');
      });

      test('required が null で latest が新しい場合', () async {
        // Arrange
        fakeStaticFileClient.setVersionInfo(
          VersionInfo(
            android: VersionInfoPlatform(
              required: null,
              latest: '1.1.0+15',
            ),
            ios: VersionInfoPlatform(
              required: null,
              latest: '1.1.0+15',
            ),
          ),
        );

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(versionControllerProvider);
        expect(state, isA<UpdateAvailable>());
      });

      test('latest が null で required が新しい場合', () async {
        // Arrange
        fakeStaticFileClient.setVersionInfo(
          VersionInfo(
            android: VersionInfoPlatform(
              required: '1.2.0+20',
              latest: null,
            ),
            ios: VersionInfoPlatform(
              required: '1.2.0+20',
              latest: null,
            ),
          ),
        );

        // Act
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert
        final state = container.read(versionControllerProvider);
        expect(state, isA<UpdateRequired>());
        final updateRequired = state as UpdateRequired;
        expect(updateRequired.latestVersion, '1.0.0+10'); // currentVersion が使用される
      });
    });

    group('状態遷移', () {
      test('UpToDate から UpdateAvailable への遷移', () async {
        // Arrange - 最初は最新
        fakeStaticFileClient.setVersionInfo(
          VersionInfo(
            android: VersionInfoPlatform(
              required: '1.0.0+10',
              latest: '1.0.0+10',
            ),
            ios: VersionInfoPlatform(
              required: '1.0.0+10',
              latest: '1.0.0+10',
            ),
          ),
        );

        // Act - 初回チェック
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert - UpToDate 状態
        var state = container.read(versionControllerProvider);
        expect(state, isA<UpToDate>());

        // Arrange - 新しいバージョンが利用可能になる
        fakeStaticFileClient.setVersionInfo(
          VersionInfo(
            android: VersionInfoPlatform(
              required: '1.0.0+10',
              latest: '1.1.0+15',
            ),
            ios: VersionInfoPlatform(
              required: '1.0.0+10',
              latest: '1.1.0+15',
            ),
          ),
        );

        // Act - 再チェック
        await controller.startObserving(true);

        // Assert - UpdateAvailable 状態
        state = container.read(versionControllerProvider);
        expect(state, isA<UpdateAvailable>());
      });

      test('UpdateAvailable から UpdateRequired への遷移', () async {
        // Arrange - 最初は任意アップデート
        fakeStaticFileClient.setVersionInfo(
          VersionInfo(
            android: VersionInfoPlatform(
              required: '1.0.0+10',
              latest: '1.1.0+15',
            ),
            ios: VersionInfoPlatform(
              required: '1.0.0+10',
              latest: '1.1.0+15',
            ),
          ),
        );

        // Act - 初回チェック
        final controller = container.read(versionControllerProvider.notifier);
        await controller.startObserving(true);

        // Assert - UpdateAvailable 状態
        var state = container.read(versionControllerProvider);
        expect(state, isA<UpdateAvailable>());

        // Arrange - 強制アップデートが必要になる
        fakeStaticFileClient.setVersionInfo(
          VersionInfo(
            android: VersionInfoPlatform(
              required: '1.2.0+20',
              latest: '1.2.0+20',
            ),
            ios: VersionInfoPlatform(
              required: '1.2.0+20',
              latest: '1.2.0+20',
            ),
          ),
        );

        // Act - 再チェック
        await controller.startObserving(true);

        // Assert - UpdateRequired 状態
        state = container.read(versionControllerProvider);
        expect(state, isA<UpdateRequired>());
      });
    });
  });
}

